<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Session.php'; require_once __DIR__.'/../includes/Auth.php'; Session::start();Auth::requireAdmin(); $db=Database::getInstance();$msg='';$err=''; if($_SERVER['REQUEST_METHOD']==='POST'){if(!Auth::validateCsrf()){$err='安全验证失败。';}else{$a=$_POST['action']??'';if($a==='save_settings'){$st=['site_name'=>trim($_POST['site_name']??''),'site_description'=>trim($_POST['site_description']??''),'check_interval'=>(int)($_POST['check_interval']??300),'history_days'=>(int)($_POST['history_days']??90),'timezone'=>trim($_POST['timezone']??'Asia/Shanghai'),'public_page_enabled'=>isset($_POST['public_page_enabled'])?'1':'0','allow_public_api'=>isset($_POST['allow_public_api'])?'1':'0'];foreach($st as $k=>$v){if($db->exists('settings','`key`=?',[$k]))$db->update('settings',['value'=>$v],'`key`=?',[$k]);else $db->insert('settings',['key'=>$k,'value'=>$v]);}$msg='设置已保存。';}elseif($a==='change_password'){$cp=$_POST['current_password']??'';$np=$_POST['new_password']??'';$cp2=$_POST['confirm_password']??'';if(empty($cp)||empty($np))$err='请输入密码。';elseif($np!==$cp2)$err='两次密码不一致。';elseif(strlen($np)<6)$err='密码至少6个字符。';elseif(Auth::changePassword(Auth::id(),$cp,$np))$msg='密码修改成功。';else $err='当前密码错误。';}}} $as=$db->fetchAll("SELECT `key`,`value` FROM `settings`");$st=[];foreach($as as $s)$st[$s['key']]=$s['value'];$u=Auth::user();?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>系统设置 - <?php echo APP_NAME;?></title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link href="/assets/css/admin.css" rel="stylesheet"></head><body><div class="admin-layout"><?php include __DIR__.'/sidebar.php';?><main class="main-content"><div class="top-bar"><h2>系统设置</h2><div class="top-bar-right"><span class="user-info"><span class="material-icons">person</span><?php echo e($u['username']);?></span></div></div><?php if($msg):?><div class="alert alert-success"><?php echo e($msg);?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?php echo e($err);?></div><?php endif;?><div class="card"><div class="card-header"><h3>基本设置</h3></div><div class="card-body"><form method="POST" class="form"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="save_settings"><div class="form-row"><div class="form-group"><label>站点名称</label><input type="text" name="site_name" value="<?php echo e($st['site_name']??'XINYU Status Monitor');?>"></div><div class="form-group"><label>描述</label><input type="text" name="site_description" value="<?php echo e($st['site_description']??'');?>"></div></div><div class="form-row"><div class="form-group"><label>检测间隔(秒)</label><input type="number" name="check_interval" value="<?php echo e($st['check_interval']??'300');?>" min="60"></div><div class="form-group"><label>历史保留天数</label><input type="number" name="history_days" value="<?php echo e($st['history_days']??'90');?>" min="7"></div></div><div class="form-group"><label>时区</label><select name="timezone"><?php foreach(['Asia/Shanghai','Asia/Tokyo','Asia/Seoul','Asia/Singapore','America/New_York','America/Los_Angeles','Europe/London','Europe/Berlin'] as $tz):?><option value="<?php echo $tz;?>" <?php echo ($st['timezone']??'Asia/Shanghai')===$tz?'selected':'';?>><?php echo $tz;?></option><?php endforeach;?></select></div><div class="form-row form-checks"><label class="checkbox-label"><input type="checkbox" name="public_page_enabled" <?php echo ($st['public_page_enabled']??'1')==='1'?'checked':'';?>> 启用公开状态页</label><label class="checkbox-label"><input type="checkbox" name="allow_public_api" <?php echo ($st['allow_public_api']??'1')==='1'?'checked':'';?>> 启用公开API</label></div><button type="submit" class="btn btn-primary">保存设置</button></form></div></div><div class="card"><div class="card-header"><h3>修改密码</h3></div><div class="card-body"><form method="POST" class="form"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="change_password"><div class="form-group"><label>当前密码</label><input type="password" name="current_password" required></div><div class="form-row"><div class="form-group"><label>新密码</label><input type="password" name="new_password" required minlength="6"></div><div class="form-group"><label>确认密码</label><input type="password" name="confirm_password" required minlength="6"></div></div><button type="submit" class="btn btn-primary">修改密码</button></form></div></div><div class="card"><div class="card-header"><h3>系统信息</h3></div><div class="card-body"><table class="table"><tr><td>系统版本</td><td><?php echo APP_VERSION;?></td></tr><tr><td>PHP</td><td><?php echo PHP_VERSION;?></td></tr><tr><td>MySQL</td><td><?php try{echo $db->getPdo()->getAttribute(PDO::ATTR_SERVER_VERSION);}catch(Exception $e){echo 'N/A';}?></td></tr><tr><td>Redis</td><td><?php echo RedisClient::getInstance()->isConnected()?'已连接':'未连接';?></td></tr><tr><td>服务器时间</td><td><?php echo date('Y-m-d H:i:s');?></td></tr></table></div></div></main></div></body></html>